import json,glob,os,re
from datetime import date
TODAY=date(2026,6,18)
universe=['GOOG','META','AMZN','NVDA','ASML','NFLX','ADYEN.AS']
alias={'GOOG':['GOOG','GOOGL']}
def files_for(t):
    names=alias.get(t,[t])
    fs=[]
    for n in names:
        for f in glob.glob(f'reports/{n}_*.json'):
            m=re.search(r'_(\d{8})\.json$',f)
            if m: fs.append((m.group(1),f))
    return sorted(fs,key=lambda x:x[0],reverse=True)
for t in universe:
    fs=files_for(t)
    model=None;model_file=None;model_date=None
    signal_file=None;screen_file=None
    price=None;price_src=None;price_file=None
    for d,f in fs:
        j=json.load(open(f))
        st=j.get('stages',{})
        if model is None and (st.get('model') or {}).get('intrinsic_value_range',{}).get('base') not in (None,0):
            model=st['model'];model_file=f;model_date=d
        if signal_file is None and st.get('signal') is not None:
            signal_file=f
        if screen_file is None and st.get('screen') is not None:
            screen_file=f
    # price: fallback signal->screen->model, newest non-null
    for stage in ['signal','screen','model']:
        if price is not None: break
        for d,f in fs:
            j=json.load(open(f)); s=(j.get('stages',{}).get(stage) or {})
            cp=s.get('current_price')
            if cp is not None:
                price=cp;price_src=stage;price_file=f;break
    md=None;stale=None
    if model_date:
        y,m,dd=int(model_date[:4]),int(model_date[4:6]),int(model_date[6:8])
        days=(TODAY-date(y,m,dd)).days; md=f'{y:04d}-{m:02d}-{dd:02d}';stale=days>14
        stale=f'{days}d {\"STALE\" if days>14 else \"fresh\"}'
    ivr=(model or {}).get('intrinsic_value_range') or {}
    print(f'{t}: model_file={os.path.basename(model_file) if model_file else None} base={ivr.get(\"base\")} rvp={(model or {}).get(\"range_vs_price\")} price={price}({price_src}) stale={stale} signal={os.path.basename(signal_file) if signal_file else None} screen={os.path.basename(screen_file) if screen_file else None}')
"

