import sys

print("[yf] yfinance MCP server ready", file=sys.stderr)

from mcp.server.fastmcp import FastMCP
from tools import YFNoDataError, FXNoDataError, get_analyst_targets as _get_analyst_targets, get_earnings_history as _get_earnings_history, get_estimates as _get_estimates, get_financials as _get_financials, get_fx_rate as _get_fx_rate, get_ratios as _get_ratios, get_total_return_cagr as _get_total_return_cagr

mcp = FastMCP("yf")


@mcp.tool()
def get_earnings_history(ticker: str, n: int = 4) -> list:
    """Last n quarters of EPS history: quarter, reported_eps, estimated_eps, surprise_pct. Max 4q (yfinance cap)."""
    return _get_earnings_history(ticker, n)


@mcp.tool()
def get_analyst_targets(ticker: str) -> dict:
    """Analyst price targets and buy/hold/sell counts: avg_target, high_target, low_target, buy_count, hold_count, sell_count."""
    return _get_analyst_targets(ticker)


@mcp.tool()
def get_ratios(ticker: str) -> dict:
    """Valuation ratios for a ticker: pe_ratio, ps_ratio, ev_ebitda, pfcf, ev_revenue."""
    return _get_ratios(ticker)


@mcp.tool()
def get_estimates(ticker: str) -> dict:
    """NTM consensus estimates: ntm_eps, ntm_revenue, analyst_count."""
    return _get_estimates(ticker)


@mcp.tool()
def get_fx_rate(base: str, quote: str) -> dict:
    """Latest daily close FX rate for base→quote (e.g. USD→KZT): base, quote, rate, date, source."""
    return _get_fx_rate(base, quote)


@mcp.tool()
def get_financials(ticker: str, period: str = "annual") -> dict:
    """Multi-year financials: revenue, operating_income, net_income, free_cash_flow, stock_based_compensation, total_debt, cash."""
    return _get_financials(ticker, period)


@mcp.tool()
def get_total_return_cagr(ticker: str, years: int = 5) -> dict:
    """Trailing total-return CAGR (auto-adjusted Close folds in dividends + splits) over N years. Use for SPY/QQQ benchmark comparators."""
    return _get_total_return_cagr(ticker, years)


if __name__ == "__main__":
    mcp.run()

import sys

print("[edgar] EDGAR MCP server ready", file=sys.stderr)

from mcp.server.fastmcp import FastMCP
from tools import (
    EDGARNoDataError,
    get_filing_facts as _get_filing_facts,
    get_filing_text as _get_filing_text,
    get_revenue_segments as _get_revenue_segments,
    get_sbc as _get_sbc,
    search_filings as _search_filings,
)

mcp = FastMCP("edgar")


@mcp.tool()
def search_filings(ticker: str, form_type: str = "10-K") -> list:
    """Recent EDGAR filings for a ticker. Returns accession_number, filing_date, form."""
    return _search_filings(ticker, form_type)


@mcp.tool()
def get_filing_facts(ticker: str, concept: str) -> dict:
    """Most recent annual 10-K value for an XBRL concept (us-gaap namespace).

    Example: get_filing_facts("CRM", "ShareBasedCompensation") returns SBC in USD.
    """
    return _get_filing_facts(ticker, concept)


@mcp.tool()
def get_sbc(ticker: str, periods: int = 4) -> dict:
    """Multi-year stock-based compensation from EDGAR XBRL facts.

    Fallback for /stock-signal when yfinance returns null SBC. Covers US filers
    (10-K, us-gaap) and foreign private issuers (20-F, ifrs-full — e.g. KSPI).

    Example: get_sbc("KSPI", 4) returns 4 years of SBC in KZT from the 20-F facts.
    Returns {ticker, filing_type, currency, periods:[{fiscal_year, sbc, source}]}.
    Raises EDGARNoDataError when no SBC concept is present in any annual filing
    (treat as "SBC line not present" — the issuer may genuinely report $0 SBC).
    """
    return _get_sbc(ticker, periods)


@mcp.tool()
def get_filing_text(accession_number: str, section: str) -> str:
    """Return plain text of a named section from an EDGAR 10-K filing.

    accession_number: e.g. "0001045810-24-000010" (from search_filings).
    section: "MD&A", "Risk Factors", "Business", or "Financial Statements".
    """
    return _get_filing_text(accession_number, section)


@mcp.tool()
def get_revenue_segments(ticker: str) -> list:
    """Revenue breakdown by business segment from EDGAR XBRL facts.

    Returns a list of {'name': str, 'revenue': int} dicts sorted by revenue
    descending.  Returns [] for single-segment companies — never raises for
    missing segment data.
    """
    return _get_revenue_segments(ticker)


if __name__ == "__main__":
    mcp.run()

